#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <functional> // For std::function
#include <utility>    // For std::pair

extern void solve(); // The user's solution function

std::string run_solution_and_capture_output(const std::string& input_str) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    solve();

    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return ss_output.str();
}

// Helper to normalize newlines and trim trailing whitespace for comparison
std::string normalize_output(std::string s) {
    // Replace CRLF with LF
    size_t pos = 0;
    while ((pos = s.find("\r\n", pos)) != std::string::npos) {
        s.replace(pos, 2, "\n");
    }
    // Remove trailing newlines/spaces
    while (!s.empty() && (s.back() == '\n' || s.back() == ' ' || s.back() == '\r')) {
        s.pop_back();
    }
    s += '\n'; // Ensure a single trailing newline for consistency
    return s;
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"10\n20\n30\n0\n", "Enter positive integers (0 to stop):\nEnter number: Enter number: Enter number: Enter number: Sum: 60\n"},
        {"0\n", "Enter positive integers (0 to stop):\nEnter number: Sum: 0\n"},
        {"5\n-2\n10\nabc\n20\n0\n", "Enter positive integers (0 to stop):\nEnter number: Enter number: Invalid input: Please enter a positive integer. (Negative numbers will be ignored.)\nEnter number: Enter number: Invalid input: Please enter an integer.\nEnter number: Enter number: Sum: 35\n"},
        {"1\n2\n3\n-4\n5\n0\n", "Enter positive integers (0 to stop):\nEnter number: Enter number: Enter number: Enter number: Invalid input: Please enter a positive integer. (Negative numbers will be ignored.)\nEnter number: Enter number: Sum: 11\n"}
    };

    bool all_passed = true;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        const std::string& input = test_cases[i].first;
        const std::string& expected_raw = test_cases[i].second;

        std::cout << "Running test case " << i + 1 << "...\n";
        std::string actual_output_raw = run_solution_and_capture_output(input);

        std::string actual_output = normalize_output(actual_output_raw);
        std::string expected_output = normalize_output(expected_raw);

        if (actual_output == expected_output) {
            std::cout << "Test Case " << i + 1 << " Passed.\n";
        } else {
            std::cout << "Test Case " << i + 1 << " Failed.\n";
            std::cout << "Input:\n" << input << "--END_INPUT--\n";
            std::cout << "Expected:\n" << expected_output << "--END_EXPECTED--\n";
            std::cout << "Actual:\n" << actual_output << "--END_ACTUAL--\n";
            all_passed = false;
        }
        std::cout << std::string(30, '-') << "\n";
    }

    if (all_passed) {
        std::cout << "All test cases passed!\n";
        return 0;
    } else {
        std::cout << "Some test cases failed.\n";
        return 1;
    }
}
